module RefModule(
        input   wire        clk,
        input   wire        reset,
        input   wire[31:0]  next_pc_pc_reg_i,
        output  wire[31:0]  next_pc_pc_reg_o
    );reg [31:0] next_pc_pc_reg;

    wire __next_pc_pc_reg_o_tmp = next_pc_pc_reg;
    assign next_pc_pc_reg_o = __next_pc_pc_reg_o_tmp;

    always @(posedge clk or posedge reset)
    if (reset)
        next_pc_pc_reg <= 31'b0;
    else
        next_pc_pc_reg <= next_pc_pc_reg_i;

endmodule
